sql:
SELECT objective_name
FROM objectives
WHERE priority_level > 2;

SELECT program_name, start_date
FROM traffic_safety_programs
WHERE start_date LIKE '2021%' OR end_date LIKE '2021%';

SELECT program_name, SUM(budget) AS total_budget
FROM traffic_safety_programs
GROUP BY program_name;

SELECT crash_type, COUNT(*) AS crash_count
FROM crash_data
GROUP BY crash_type;

SELECT COUNT(*) 
FROM crash_data 
WHERE crash_severity = 'Severe';

SELECT COUNT(*) AS total_assignments
FROM action_item_assignments
WHERE team_member_id = 1;

external_knowledge:
- 'contributors' refers to team members with the 'contributor' role; 
- 'completed' action items are those with a status_id matching the status_name 'completed' in the statuses table; 
- 'deadline reminder' and 'assignment notification' are types of notifications sent to team members; 
- 'average completion time' is calculated by subtracting the assignment date from the completion date.

sql:
SELECT status, COUNT(*) as action_item_count
FROM action_items
WHERE status = 1;

SELECT assignment_id, feedback
FROM action_item_assignments
WHERE feedback IS NOT NULL;

SELECT action_item_id, end_date 
FROM action_items 
WHERE status = 1;

SELECT status, COUNT(*) AS action_item_count
FROM action_items
GROUP BY status;

SELECT COUNT(*) AS number_of_analyses
FROM crash_analysis
WHERE analysis_team = 'Data Analysis Team';

SELECT crash_location, crash_severity
FROM crash_data
WHERE weather_conditions = 'Rainy';
